--
-- Table structure for table `symmetexei`
--

DROP TABLE IF EXISTS `symmetexei`;

CREATE TABLE `symmetexei` (
  `ID_PAIKTI` int NOT NULL,
  `ID_AGONA` int NOT NULL,
  `LEPTA_SYMMETOXIS` int DEFAULT '0',
  `GKOL` int DEFAULT '0',
  `ASIST` int DEFAULT '0',
  `KITRINES_KARTES` int DEFAULT '0',
  `KOKKINES_KARTES` int DEFAULT '0',
  `MVP` tinyint(1) DEFAULT '0',
  `CAPTAIN` tinyint(1) DEFAULT '0',
  `KODIKOS_APODOSIS` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`ID_PAIKTI`,`ID_AGONA`),
  KEY `FK_symmetexei_agona` (`ID_AGONA`),
  CONSTRAINT `FK_symmetexei_agona` FOREIGN KEY (`ID_AGONA`) REFERENCES `agonas` (`ID_AGONA`) ON DELETE CASCADE,
  CONSTRAINT `FK_symmetexei_paikti` FOREIGN KEY (`ID_PAIKTI`) REFERENCES `paikti` (`ID_PAIKTI`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

